sections.example:
a = {1, 2, 3, 4}
b = {3, 4, 5, 6}

print(a & b)   # {3, 4}  — intersection
print(a | b)   # {1, 2, 3, 4, 5, 6}  — union
print(a - b)   # {1, 2}  — in a but not b
print(b - a)   # {5, 6}  — in b but not a

# Method syntax also works
print(a.intersection(b))  # {3, 4}

def first_duplicate(nums):
    seen = set()
    for num in nums:
        if num in seen:
            return num
        seen.add(num)
    return -1

print(first_duplicate([2, 1, 3, 5, 3, 2]))  # 3
print(first_duplicate([1, 2, 3]))            # -1
